#include "triplet_margin_loss_custom_tiling.h"
#include "register/op_def_registry.h"

namespace optiling {

static constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
static constexpr uint32_t ALIGN_ELEMS = 8;
static constexpr uint32_t HARD_CAP_ROWS = 32768;

static inline uint32_t AlignDown(uint32_t x, uint32_t a)
{
    return (x / a) * a;
}

static inline uint32_t CeilDiv(uint32_t a, uint32_t b)
{
    return (a + b - 1u) / b;
}

static ge::graphStatus TilingFunc(gert::TilingContext *context)
{
    TripletMarginLossCustomTilingData tiling;

    // Use GetInputShape which directly returns the shape (origin shape)
    const auto *shape = context->GetInputShape(0);
    const uint32_t n = static_cast<uint32_t>(shape->GetDim(0));
    const uint32_t d = static_cast<uint32_t>(shape->GetDim(1));

    const gert::RuntimeAttrs *attrs = context->GetAttrs();
    const float *margin = attrs->GetAttrPointer<float>(0);

    const uint32_t rowCostFloats = 5 * d;
    const uint32_t maxRows = UB_BUDGET_BYTES / (rowCostFloats * sizeof(float));
    uint32_t tileBatch = maxRows;
    if (tileBatch < 1) tileBatch = 1;
    if (tileBatch > HARD_CAP_ROWS) tileBatch = HARD_CAP_ROWS;
    if (tileBatch > n) tileBatch = n;

    tileBatch = AlignDown(tileBatch, ALIGN_ELEMS);
    if (tileBatch < 1) tileBatch = 1;

    uint32_t blockDim = CeilDiv(n, tileBatch);
    if (blockDim < 8) blockDim = 8;
    if (blockDim > 24) blockDim = 24;

    context->SetBlockDim(blockDim);

    tiling.set_totalRows(n);
    tiling.set_dim(d);
    tiling.set_tileBatch(tileBatch);
    tiling.set_blockDim(blockDim);
    tiling.set_margin(*margin);

    tiling.SaveToBuffer(context->GetRawTilingData()->GetData(),
                        context->GetRawTilingData()->GetCapacity());
    context->GetRawTilingData()->SetDataSize(tiling.GetDataSize());

    size_t *currentWorkspace = context->GetWorkspaceSizes(1);
    currentWorkspace[0] = 0;
    return ge::GRAPH_SUCCESS;
}

} // namespace optiling

namespace ge {
static ge::graphStatus InferShape(gert::InferShapeContext *context)
{
    // Compute blockDim same as TilingFunc to set output shape
    const auto *shape = context->GetInputShape(0);
    const uint32_t n = static_cast<uint32_t>(shape->GetDim(0));
    const uint32_t d = static_cast<uint32_t>(shape->GetDim(1));

    constexpr uint32_t UB_BUDGET_BYTES = 192 * 1024;
    constexpr uint32_t ALIGN_ELEMS = 8;
    constexpr uint32_t HARD_CAP_ROWS = 32768;

    const uint32_t rowCostFloats = 5 * d;
    const uint32_t maxRows = UB_BUDGET_BYTES / (rowCostFloats * sizeof(float));
    uint32_t tileBatch = maxRows;
    if (tileBatch < 1) tileBatch = 1;
    if (tileBatch > HARD_CAP_ROWS) tileBatch = HARD_CAP_ROWS;
    if (tileBatch > n) tileBatch = n;
    tileBatch = (tileBatch / ALIGN_ELEMS) * ALIGN_ELEMS;
    if (tileBatch < 1) tileBatch = 1;

    uint32_t blockDim = (n + tileBatch - 1) / tileBatch;
    if (blockDim < 8) blockDim = 8;
    if (blockDim > 24) blockDim = 24;

    gert::Shape *loss_shape = context->GetOutputShape(0);
    loss_shape->SetDimNum(1);
    loss_shape->SetDim(0, static_cast<int64_t>(blockDim));
    return GRAPH_SUCCESS;
}

